def simple_kalman_smooth(measurements, initial_estimate):
    if len(measurements) == 0:
        return []
    if len(measurements) == 1:
        return [measurements[0]]

    smoothed_measurements = [initial_estimate]

    for i in range(1, len(measurements)):
        if i == 1:
            new_estimate = (initial_estimate + measurements[1]) / 2
        else:
            new_estimate = (smoothed_measurements[i-1] + measurements[i]) / 2
        smoothed_measurements.append(new_estimate)

    return smoothed_measurements

