    def __init__(self, bounding_volume=None, left=None, right=None):
        self.bounding_volume = bounding_volume
        self.left = left
        self.right = right
        self.overlapping_objects = []

    def split(self, objects):
        if not objects:
            return None
        mid = len(objects) // 2
        median = sorted(objects, key=lambda x: x[1]) 
        midpoint = median[mid - 1][1]

        self.split_objects(objects, lambda x: x[1] < midpoint, self.left)
        self.split_objects(objects, lambda x: x[1] >= midpoint, self.right)

    def split_objects(self, objects, predicate, left):
        for obj in objects:
            if predicate(obj):
                left.append(obj)
            else:
                right = obj
        self.overlapping_objects = [x[0] for x in objects]  # Store the original objects, not the bounding_volume

    def report_collisions(self):
        if self.bounding_volume is None:
            return []

        self.overlapping_left = self.left.report_collisions() if self.left else []
        self.overlapping_right =

