def extract_requirements(text):
    # Patterns have been simplified to account for different ways clauses could be formed
    patterns = [
        r'(\bmust\b|\bshould\b|\bneed\b)\s+([^\.\?\!]+)', # General requirement patterns
        r'(\bmust\b|\bshould\b|\bneed\b)\s+([^\.\?\!]+)' # Handle scenarios where 'must' precedes the action
    ]
    requirements = set()

    for pattern in patterns:
        matches = re.findall(pattern, text, re.DOTALL)
        for match in matches:
            requirements.add(match[1].strip())

